+fn futex_rwlock_rdlock(word: &AtomicI32) -> c_int {
+    loop {
+        let state = word.load(Ordering::Acquire);
+        if state >= 0 {
+            if state == i32::MAX {
+                return libc::EAGAIN;
+            }
+            if word
+                .compare_exchange(state, state + 1, Ordering::Acquire, Ordering::Relaxed)
+                .is_ok()
+            {
+                return 0;
+            }
+            continue;
+        }
+
+        #[cfg(target_os = "linux")]
+        {
+            let rc = futex_wait_private(word, state);
+            if rc == 0 {
+                continue;
+            }
+            let errno = std::io::Error::last_os_error().raw_os_error().unwrap_or(0);
+            if errno == libc::EINTR || errno == libc::EAGAIN {
+                continue;
+            }
+            return if errno == 0 { libc::EAGAIN } else { errno };
+        }
+
+        #[cfg(not(target_os = "linux"))]
+        {
+            core::hint::spin_loop();
+        }
+    }
+}
+
+fn futex_rwlock_wrlock(word: &AtomicI32) -> c_int {
+    loop {
+        if word
+            .compare_exchange(0, -1, Ordering::Acquire, Ordering::Relaxed)
+            .is_ok()
+        {
+            return 0;
+        }
+
+        let state = word.load(Ordering::Relaxed);
+
+        #[cfg(target_os = "linux")]
+        {
+            let rc = futex_wait_private(word, state);
+            if rc == 0 {
+                continue;
+            }
+            let errno = std::io::Error::last_os_error().raw_os_error().unwrap_or(0);
+            if errno == libc::EINTR || errno == libc::EAGAIN {
+                continue;
+            }
+            return if errno == 0 { libc::EAGAIN } else { errno };
+        }
+
+        #[cfg(not(target_os = "linux"))]
+        {
+            core::hint::spin_loop();
+        }
+    }
+}
+
+fn futex_rwlock_unlock(word: &AtomicI32) -> c_int {
+    loop {
+        let state = word.load(Ordering::Acquire);
+        if state == 0 {
+            return libc::EPERM;
+        }
+        if state == -1 {
+            if word
+                .compare_exchange(-1, 0, Ordering::Release, Ordering::Relaxed)
+                .is_ok()
+            {
+                #[cfg(target_os = "linux")]
+                {
+                    let _ = futex_wake_private(word, i32::MAX);
+                }
+                return 0;
+            }
+            continue;
+        }
+        if state > 0 {
+            if word
+                .compare_exchange(state, state - 1, Ordering::Release, Ordering::Relaxed)
+                .is_ok()
+            {
+                if state == 1 {
+                    #[cfg(target_os = "linux")]
+                    {
+                        let _ = futex_wake_private(word, i32::MAX);
+                    }
+                }
+                return 0;
+            }
+            continue;
+        }
+        return libc::EINVAL;
+    }
+}
